data.output:
			actual = b.Owner
		case "assignee":
			actual = b.Owner
		case "parent":
			actual = b.Parent
		case "description":
			actual = b.Description
		case "acceptance":
			actual = b.Acceptance
		case "notes":
			actual = b.Notes
		default:
			// Fall back to Extra map for unknown/workflow-specific fields
			if b.Extra != nil {
				if ev, ok := b.Extra[k]; ok {
					actual = fmt.Sprintf("%v", ev)
				}
			}
		}
		if actual != v {
			return false
		}
	}
	return true
}

// Ready returns open beads whose dependencies are all closed, sorted by
// priority (0 = highest first).
func (s *Store) Ready() ([]Bead, error) {
	return s.readyFiltered(false)
}

// ReadyExecution returns ready beads that are also execution-eligible and
// not superseded. This is the filter HELIX uses for its build loop.
func (s *Store) ReadyExecution() ([]Bead, error) {
	return s.readyFiltered(true)
}

// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
// they are NOT execution-eligible: lifecycle-blocked statuses, epic
// containers, retry cooldown, execution-eligible=false, or superseded. It's
// the diagnostic the work loop emits when the execution queue is empty but
// `ddx bead ready` is not.
type ReadyExecutionBreakdown struct {
	SkippedEpics              []string
	SkippedOnCooldown         []string
	SkippedNeedsInvestigation []string
	SkippedBlocked            []string
	SkippedNotEligible        []string
	SkippedSuperseded         []string
	NextRetryAfter            string
}

func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
	out := ReadyExecutionBreakdown{}
	beads, err := s.ReadAll()
	if err != nil {
		return out, err
	}
	statusMap := make(map[string]string)
	childCount := make(map[string]int)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
		if b.Parent != "" {
			childCount[b.Parent]++
		}
	}
	now := time.Now().UTC()
	var soonestRetry time.Time
	for _, b := range beads {
		if !depsSatisfied(b, statusMap) {
			continue
		}
		switch b.Status {
		case StatusBlocked, StatusProposed, StatusCancelled:
			out.SkippedBlocked = append(out.SkippedBlocked, b.ID)
			continue
		case StatusInProgress:
			if !claimLeaseIsStale(s, b.Extra, b.ID) {
				continue
			}
		case StatusOpen:
		default:
			continue
		}
		if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
			if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
				if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
					out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
					if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
						soonestRetry = retryAfter
					}
					continue
				}
			}
		}
		if isOrdinaryEpicContainer(b, childCount[b.ID]) {
			out.SkippedEpics = append(out.SkippedEpics, b.ID)
			continue
		}
		if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
			out.SkippedNeedsInvestigation = append(out.SkippedNeedsInvestigation, b.ID)
			continue
		}
		if eligible, ok := b.Extra["execution-eligible"]; ok {
			if val, isBool := eligible.(bool); isBool && !val {
				out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
				continue
			}
		}
		if sup, ok := b.Extra["superseded-by"]; ok {
			if s, isStr := sup.(string); isStr && s != "" {
				out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
				continue
			}
		}
	}
	if !soonestRetry.IsZero() {
		out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
	}
	return out, nil
}

func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
	beads, err := s.ReadAll()
	if err != nil {
		return nil, err
	}
	statusMap := make(map[string]string)
	childCount := make(map[string]int)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
		if b.Parent != "" {
			childCount[b.Parent]++
		}
	}

	var ready []Bead
	for _, b := range beads {
		if b.Status != StatusOpen {
			// Surface stalled in_progress beads so a fresh worker can
			// reclaim them atomically in Claim().
			if executionOnly && b.Status == StatusInProgress && claimLeaseIsStale(s, b.Extra, b.ID) {
				// fall through to dependency check below
			} else {
				continue
			}
		}
		allSatisfied := true
		for _, depID := range b.DepIDs() {
			if statusMap[depID] != StatusClosed {
				allSatisfied = false
				break
			}
		}
		if !allSatisfied {
			continue
		}
		if executionOnly {
			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
				continue
			}
			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
				continue
			}
			// Filter by execution-eligible (default true if absent)
			eligible, ok := b.Extra["execution-eligible"]
			if ok {
				if val, isBool := eligible.(bool); isBool && !val {
					continue
				}
			}
			// Filter out superseded beads
			if sup, ok := b.Extra["superseded-by"]; ok {
				if s, isStr := sup.(string); isStr && s != "" {
					continue
				}
			}
			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
						continue
					}
				}
			}
		}
		ready = append(ready, b)
	}

	sortBeadsForQueue(ready)

	return ready, nil
}

// Blocked returns open beads with at least one unclosed dependency.
func (s *Store) Blocked() ([]Bead, error) {
	beads, err := s.ReadAll()
	if err != nil {
		return nil, err
	}
	statusMap := make(map[string]string)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
	}

	var blocked []Bead
	for _, b := range beads {
		if b.Status != StatusOpen {
			continue
		}
		for _, depID := range b.DepIDs() {
			if statusMap[depID] != StatusClosed {
				blocked = append(blocked, b)
				break
			}
		}
	}
	sortBeadsForQueue(blocked)
	return blocked, nil
}

// BlockedAll returns open beads that are currently not runnable, classified
// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
// that is both dep-blocked and cooldown-parked is reported as dependency-
// blocked, because deps are the stronger blocker.
func (s *Store) BlockedAll() ([]BlockedBead, error) {
	beads, err := s.ReadAll()
	if err != nil {
		return nil, err
	}
	statusMap := make(map[string]string)
	childCount := make(map[string]int)
	for _, b := range beads {
		statusMap[b.ID] = b.Status
		if b.Parent != "" {
			childCount[b.Parent]++
		}
	}

	now := time.Now().UTC()
	var entries []BlockedBead
	for _, b := range beads {
		if b.Status != StatusOpen && b.Status != StatusBlocked {
			continue
		}

		var unclosed []string
		for _, depID := range b.DepIDs() {
			if statusMap[depID] != StatusClosed {
				unclosed = append(unclosed, depID)
			}
		}
		if len(unclosed) > 0 {
			entries = append(entries, BlockedBead{
				Bead: b,
				Blocker: Blocker{
					Kind:           BlockerKindDependency,
					UnclosedDepIDs: unclosed,
				},
			})
			continue
		}
		if b.Status == StatusBlocked {
			entries = append(entries, BlockedBead{
				Bead: b,
				Blocker: Blocker{
					Kind:   BlockerKindBlockedStatus,
					Reason: "persisted blocked status",
				},
			})
			continue
		}

		if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
			entries = append(entries, BlockedBead{
				Bead: b,
				Blocker: Blocker{
					Kind:       BlockerKindNeedsInvestigation,
					LastStatus: "no_changes",
					Reason:     "triage needs investigation before retry",
				},
			})
			continue
		}
		if isOrdinaryEpicContainer(b, childCount[b.ID]) {
			entries = append(entries, BlockedBead{
				Bead: b,
				Blocker: Blocker{
					Kind:   BlockerKindEpicOnly,
					Reason: "ordinary ddx work skips epic/container beads",
				},
			})
			continue
		}

		if eligible, ok := b.Extra["execution-eligible"]; ok {
			if val, isBool := eligible.(bool); isBool && !val {
				reason, _ := b.Extra["execution-skip-reason"].(string)
				entries = append(entries, BlockedBead{
					Bead: b,
					Blocker: Blocker{
						Kind:   BlockerKindNotEligible,
						Reason: reason,
					},
				})
				continue
			}
		}
		if sup, ok := b.Extra["superseded-by"]; ok {
			if s, isStr := sup.(string); isStr && s != "" {
				entries = append(entries, BlockedBead{
					Bead: b,
					Blocker: Blocker{
						Kind:   BlockerKindSuperseded,
						Reason: s,
					},
				})
				continue
			}
		}

		retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
		if !ok {
			continue
		}
		retryAfterStr, isStr := retryAfterRaw.(string)
		if !isStr || retryAfterStr == "" {
			continue
		}
		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
		if err != nil || !retryAfter.After(now) {
			continue
		}
		blocker := Blocker{
			Kind:           BlockerKindRetryCooldown,
			NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
		}
		if v, ok := b.Extra["execute-loop-last-status"]; ok {
			if s, ok := v.(string); ok {
				blocker.LastStatus = s
			}
		}
		if v, ok := b.Extra["execute-loop-last-detail"]; ok {
			if s, ok := v.(string); ok {
				blocker.LastDetail = s
			}
		}
		entries = append(entries, BlockedBead{
			Bead:    b,
			Blocker: blocker,
		})
	}

	sort.SliceStable(entries, func(i, j int) bool {
		if entries[i].Priority != entries[j].Priority {
			return entries[i].Priority < entries[j].Priority
		}
		if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
			return entries[i].CreatedAt.Before(entries[j].CreatedAt)
		}
		return entries[i].ID < entries[j].ID
	})
	return entries, nil
}

func depsSatisfied(b Bead, statusMap map[string]string) bool {
	for _, depID := range b.DepIDs() {
		if statusMap[depID] != StatusClosed {
			return false
		}
	}
	return true
}

func isOrdinaryEpicContainer(b Bead, childCount int) bool {
	issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
	title := strings.ToLower(strings.TrimSpace(b.Title))
	return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
}

func sortBeadsForQueue(beads []Bead) {
	sort.SliceStable(beads, func(i, j int) bool {
		if beads[i].Priority != beads[j].Priority {
			return beads[i].Priority < beads[j].Priority
		}
		ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
		jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
		if iok != jok {
			return iok
		}
		if iok && jok && ir != jr {
			return ir < jr
		}
		if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
			return beads[i].CreatedAt.Before(beads[j].CreatedAt)
		}
		return beads[i].ID < beads[j].ID
	})
}

func parseQueueRank(raw any) (int, bool) {
	switch v := raw.(type) {
	case int:
		return v, true
	case int8:
		return int(v), true
	case int16:
		return int(v), true
	case int32:
		return int(v), true
	case int64:
		return int(v), true
	case uint:
		return int(v), true

		return int(v), true
	case uint8:
		return int(v), true
	case uint16:
		return int(v), true
	case uint32:
		return int(v), true
	case uint64:
		return int(v), true
	case float32:
		return int(v), v == float32(int(v))
	case float64:
		return int(v), v == float64(int(v))
	case json.Number:
		if n, err := v.Int64(); err == nil {
			return int(n), true
		}
		if f, err := v.Float64(); err == nil {
			return int(f), f == float64(int(f))
		}
	case string:
		if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
			return n, true
		}
	}
	return 0, false
}

